def fast_sort(arr):
    if not arr:
        return []
    max_val = arr[0]
    min_val = arr[0]
    for x in arr:
        if x > max_val:
            max_val = x
        if x < min_val:
            min_val = x
    range_val = max_val - min_val + 1
    if range_val > 10 * len(arr):
        if len(arr) <= 1:
            return arr[:]
        mid = len(arr) // 2
        left = fast_sort(arr[:mid])
        right = fast_sort(arr[mid:])
        merged = []
        i = j = 0
        while i < len(left) and j < len(right):
            if left[i] <= right[j]:
                merged.append(left[i])
                i += 1
            else:
                merged.append(right[j])
                j += 1
        merged.extend(left[i:])
        merged.extend(right[j:])
        return merged
    count = [0] * range_val
    for x in arr:
        count[x - min_val] += 1
    result = []
    for i in range(range_val):
        result.extend([i + min_val] * count[i])
    return result

